import React from 'react';
import { TiWeatherSunny, TiWeatherNight } from "react-icons/ti"

const clampValueInRange = (value, start, end) => Math.min(Math.max(value, start), end)
const valueToPercent = (value, start, end) => (value - start) / Math.abs(end - start) * 100
const clampValuePercent = (value, start, end) => {
    // return value in range 0 - 100
    value = clampValueInRange(value, start, end)
    return valueToPercent(value, start, end)
}

const mapPercentToValue = (percent, min, max ) => min + (max-min)*percent/100



class SLider extends React.Component {

    componentDidMount() {
        const { top, height, left, width } = this.bar.getBoundingClientRect()
        this.min = top;
        this.max = top + height;
    }

    setNewValue = (val) => {
        this.setState({ valueInPercent: val })
        if(this.props.onChange){
            this.props.onChange(mapPercentToValue(val, this.props.min, this.props.max))
        }
    }
    handleTouchStart = (event) => {
        //event prevent default
        event.preventDefault()
        this.touch = event.changedTouches[0]
        if (this.touch) {
            this.touchID = this.touch.identifier
        }
        this.setNewValue(clampValuePercent(this.touch.clientY, this.min, this.max))
    }

    handleTouchMove = (event) => {
        this.touch = event.changedTouches[0]
        this.setNewValue(clampValuePercent(this.touch.clientY, this.min, this.max))

    }



    handleMouseMove = (event) => {
        event.preventDefault()
        if(event.buttons === 1){

            this.setNewValue(clampValuePercent(event.clientY, this.min, this.max))
            
        }
        else if(event.buttons === 0 && event.target !== this.wrapper){

            document.body.removeEventListener('mousemove', this.handleMouseMove)
        }
    }

    handleMouseOut = (event) => {
        //when cursor outs of the target, checking if LMB is holding
        event.preventDefault()
        if(event.buttons === 1){
            document.body.addEventListener('mousemove', this.handleMouseMove)
        }
    }

    handleMouseMoveOver = (event) => {
        //dragging over the target div
        event.preventDefault()
        if(event.buttons === 1){
            this.setNewValue(clampValuePercent(event.clientY, this.min, this.max))
        }
    }


    state = {
        valueInPercent: 0
    }

    render() {
        const {
            direction,
            width,
            height,
            strokeWidth,
            thumbWidth,

            style,
            thumbStyle,
            barStyle
        } = this.props



        return (
            <div style={{ position: 'fixed', right: '2%', top: '40vh', width: 18, height: '10vh', margin: 0, padding: 0, }}
                onTouchStart={this.handleTouchStart}
                onTouchMove={this.handleTouchMove}
                onClick={event => { event.preventDefault(); this.setState({ valueInPercent: clampValuePercent(event.clientY, this.min, this.max) }) }}
                onMouseMove={this.handleMouseMove}
                onMouseOut={this.handleMouseOut}
                ref={ref => this.wrapper = ref}
            >
                <div style={{ display: 'flex', alignItems: 'stretch', flexDirection: 'column', height: 200 }}>

                    <div style={{ height: '20%',position:'relative', display: 'flex', justifyContent: 'center', alignItems: 'center' }}><TiWeatherSunny color='white' height='100%'></TiWeatherSunny></div>
                    <div style={{ height: '50%', position:'relative', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
                        <div className='bar'
                            style={{
                                width: 1,
                                height: '100%',
                                background: '#eee',
                            }}
                            ref={ref => this.bar = ref}
                        />
                        <div className='thumb' style={{position:'absolute' ,width: 9, height: 9, background: '#f9fbe7', borderRadius: 2,
                        top: `${this.state.valueInPercent}%`, transform: 'rotateZ(45deg)' 

                        }}
                            ref={ref => this.thumb = ref}
                        />
                    </div>
                    <div style={{ height: '20%',position:'relative', display: 'flex', justifyContent: 'center', alignItems: 'center' }}><TiWeatherNight color='white' height='100%' /></div>
                </div>
            </div>
        )
    }
}

SLider.defaultProps = {
    width: 1,
    height: '10vh',
    strokeWidth: 1,
}

export default SLider;